vi.mock('node:child_process', () => ({
  execFileSync: vi.fn(() => ' M src/hooks/src/stop/stop-failure-handler.ts\n?? new-file.ts'),
}));

// Mock session-tracker (state flush) — we verify these are called
const mockFlushEventCounter = vi.fn();
